(()=>{document.addEventListener("DOMContentLoaded",function(){let e=document.querySelector(".toc-content");if(!e)return;let c=document.querySelectorAll("h1[id], h2[id], h3[id], h4[id], h5[id], h6[id]"),n=e.querySelectorAll("a"),i={root:null,rootMargin:"0px",threshold:1},s=new IntersectionObserver(t=>{t.forEach(o=>{if(o.isIntersecting){n.forEach(d=>d.classList.remove("active"));let r=e.querySelector(`a[href="#${o.target.id}"]`);r&&r.classList.add("active")}})},i);c.forEach(t=>s.observe(t))});})();
